mapper.select:
SELECT 
    id, city_id, type, category, merchant_id, sort, 
    sale_num_month, sale_num_day, date, is_delete, 
    create_time, update_time
FROM merchant_rank_info
WHERE is_delete = 0
  AND city_id = #{cityId}
  AND type = #{type}
  AND category = #{category}
  AND date = #{date}
ORDER BY sort ASC
